# Particle Text Effect

A canvas component that cycles through a list of words by assembling and dispersing particles into each word's letterform. Particles fly in from random positions, form the text with color transitions, then dissolve on word change. Right-click and drag to scatter particles interactively.

## Use when
- Creating an interactive dark hero section where the headline is animated with particle effects.
- Showcasing a portfolio or product with rotating word particles.
- Adding a playful, kinetic text animation to a landing page section.
- Building a demo or interactive installation piece.

## Stack
- Framework: react
- Libraries: (none)
- Requires: tailwind, shadcn

## Install
```bash
# no additional packages required
```

## Component — particle-text-effect.tsx
```tsx
"use client"

import { useEffect, useRef } from "react"

interface Vector2D {
  x: number
  y: number
}

class Particle {
  pos: Vector2D = { x: 0, y: 0 }
  vel: Vector2D = { x: 0, y: 0 }
  acc: Vector2D = { x: 0, y: 0 }
  target: Vector2D = { x: 0, y: 0 }
  closeEnoughTarget = 100
  maxSpeed = 1.0
  maxForce = 0.1
  particleSize = 10
  isKilled = false
  startColor = { r: 0, g: 0, b: 0 }
  targetColor = { r: 0, g: 0, b: 0 }
  colorWeight = 0
  colorBlendRate = 0.01

  move() {
    let proximityMult = 1
    const distance = Math.sqrt(Math.pow(this.pos.x - this.target.x, 2) + Math.pow(this.pos.y - this.target.y, 2))
    if (distance < this.closeEnoughTarget) proximityMult = distance / this.closeEnoughTarget
    const towardsTarget = { x: this.target.x - this.pos.x, y: this.target.y - this.pos.y }
    const magnitude = Math.sqrt(towardsTarget.x ** 2 + towardsTarget.y ** 2)
    if (magnitude > 0) { towardsTarget.x = (towardsTarget.x / magnitude) * this.maxSpeed * proximityMult; towardsTarget.y = (towardsTarget.y / magnitude) * this.maxSpeed * proximityMult }
    const steer = { x: towardsTarget.x - this.vel.x, y: towardsTarget.y - this.vel.y }
    const steerMag = Math.sqrt(steer.x ** 2 + steer.y ** 2)
    if (steerMag > 0) { steer.x = (steer.x / steerMag) * this.maxForce; steer.y = (steer.y / steerMag) * this.maxForce }
    this.acc.x += steer.x; this.acc.y += steer.y
    this.vel.x += this.acc.x; this.vel.y += this.acc.y
    this.pos.x += this.vel.x; this.pos.y += this.vel.y
    this.acc.x = 0; this.acc.y = 0
  }

  draw(ctx: CanvasRenderingContext2D, drawAsPoints: boolean) {
    if (this.colorWeight < 1.0) this.colorWeight = Math.min(this.colorWeight + this.colorBlendRate, 1.0)
    const r = Math.round(this.startColor.r + (this.targetColor.r - this.startColor.r) * this.colorWeight)
    const g = Math.round(this.startColor.g + (this.targetColor.g - this.startColor.g) * this.colorWeight)
    const b = Math.round(this.startColor.b + (this.targetColor.b - this.startColor.b) * this.colorWeight)
    ctx.fillStyle = `rgb(${r},${g},${b})`
    if (drawAsPoints) { ctx.fillRect(this.pos.x, this.pos.y, 2, 2) }
    else { ctx.beginPath(); ctx.arc(this.pos.x, this.pos.y, this.particleSize / 2, 0, Math.PI * 2); ctx.fill() }
  }

  kill(width: number, height: number) {
    if (!this.isKilled) {
      const rx = Math.random() * 1000; const ry = Math.random() * 500
      const dx = rx - width / 2; const dy = ry - height / 2
      const mag = Math.sqrt(dx ** 2 + dy ** 2); const dist = (width + height) / 2
      this.target.x = width / 2 + (dx / mag) * dist; this.target.y = height / 2 + (dy / mag) * dist
      this.startColor = { r: this.startColor.r + (this.targetColor.r - this.startColor.r) * this.colorWeight, g: this.startColor.g + (this.targetColor.g - this.startColor.g) * this.colorWeight, b: this.startColor.b + (this.targetColor.b - this.startColor.b) * this.colorWeight }
      this.targetColor = { r: 0, g: 0, b: 0 }
      this.colorWeight = 0
      this.isKilled = true
    }
  }
}

interface ParticleTextEffectProps {
  words?: string[]
}

const DEFAULT_WORDS = ["HELLO", "DESIGN", "MOTION", "CREATE"]

export function ParticleTextEffect({ words = DEFAULT_WORDS }: ParticleTextEffectProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const animationRef = useRef<number>()
  const particlesRef = useRef<Particle[]>([])
  const frameCountRef = useRef(0)
  const wordIndexRef = useRef(0)
  const mouseRef = useRef({ x: 0, y: 0, isPressed: false, isRightClick: false })
  const pixelSteps = 6
  const drawAsPoints = true

  const nextWord = (word: string, canvas: HTMLCanvasElement) => {
    const offscreen = document.createElement("canvas")
    offscreen.width = canvas.width; offscreen.height = canvas.height
    const ctx2 = offscreen.getContext("2d")!
    ctx2.fillStyle = "white"; ctx2.font = "bold 100px Arial"
    ctx2.textAlign = "center"; ctx2.textBaseline = "middle"
    ctx2.fillText(word, canvas.width / 2, canvas.height / 2)
    const imageData = ctx2.getImageData(0, 0, canvas.width, canvas.height)
    const pixels = imageData.data
    const newColor = { r: Math.random() * 255, g: Math.random() * 255, b: Math.random() * 255 }
    const particles = particlesRef.current
    let particleIndex = 0
    const coordsIndexes: number[] = []
    for (let i = 0; i < pixels.length; i += pixelSteps * 4) coordsIndexes.push(i)
    for (let i = coordsIndexes.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [coordsIndexes[i], coordsIndexes[j]] = [coordsIndexes[j], coordsIndexes[i]] }
    for (const coordIndex of coordsIndexes) {
      if (pixels[coordIndex + 3] > 0) {
        const x = (coordIndex / 4) % canvas.width; const y = Math.floor(coordIndex / 4 / canvas.width)
        let particle: Particle
        if (particleIndex < particles.length) { particle = particles[particleIndex]; particle.isKilled = false; particleIndex++ }
        else { particle = new Particle(); const rx = Math.random() * 1000; const ry = Math.random() * 500; const dx = rx - canvas.width / 2; const dy = ry - canvas.height / 2; const mag = Math.sqrt(dx ** 2 + dy ** 2); const dist = (canvas.width + canvas.height) / 2; particle.pos.x = canvas.width / 2 + (dx / mag) * dist; particle.pos.y = canvas.height / 2 + (dy / mag) * dist; particle.maxSpeed = Math.random() * 6 + 4; particle.maxForce = particle.maxSpeed * 0.05; particle.particleSize = Math.random() * 6 + 6; particle.colorBlendRate = Math.random() * 0.0275 + 0.0025; particles.push(particle) }
        particle.startColor = { r: particle.startColor.r + (particle.targetColor.r - particle.startColor.r) * particle.colorWeight, g: particle.startColor.g + (particle.targetColor.g - particle.startColor.g) * particle.colorWeight, b: particle.startColor.b + (particle.targetColor.b - particle.startColor.b) * particle.colorWeight }
        particle.targetColor = newColor; particle.colorWeight = 0; particle.target.x = x; particle.target.y = y
      }
    }
    for (let i = particleIndex; i < particles.length; i++) particles[i].kill(canvas.width, canvas.height)
  }

  const animate = () => {
    const canvas = canvasRef.current; if (!canvas) return
    const ctx = canvas.getContext("2d")!; const particles = particlesRef.current
    ctx.fillStyle = "rgba(0,0,0,0.1)"; ctx.fillRect(0, 0, canvas.width, canvas.height)
    for (let i = particles.length - 1; i >= 0; i--) {
      const p = particles[i]; p.move(); p.draw(ctx, drawAsPoints)
      if (p.isKilled && (p.pos.x < 0 || p.pos.x > canvas.width || p.pos.y < 0 || p.pos.y > canvas.height)) particles.splice(i, 1)
    }
    if (mouseRef.current.isPressed && mouseRef.current.isRightClick) particles.forEach(p => { if (Math.sqrt((p.pos.x - mouseRef.current.x) ** 2 + (p.pos.y - mouseRef.current.y) ** 2) < 50) p.kill(canvas.width, canvas.height) })
    frameCountRef.current++
    if (frameCountRef.current % 240 === 0) { wordIndexRef.current = (wordIndexRef.current + 1) % words.length; nextWord(words[wordIndexRef.current], canvas) }
    animationRef.current = requestAnimationFrame(animate)
  }

  useEffect(() => {
    const canvas = canvasRef.current; if (!canvas) return
    canvas.width = 1000; canvas.height = 500
    nextWord(words[0], canvas); animate()
    const down = (e: MouseEvent) => { mouseRef.current.isPressed = true; mouseRef.current.isRightClick = e.button === 2; const r = canvas.getBoundingClientRect(); mouseRef.current.x = e.clientX - r.left; mouseRef.current.y = e.clientY - r.top }
    const up = () => { mouseRef.current.isPressed = false; mouseRef.current.isRightClick = false }
    const move = (e: MouseEvent) => { const r = canvas.getBoundingClientRect(); mouseRef.current.x = e.clientX - r.left; mouseRef.current.y = e.clientY - r.top }
    const menu = (e: MouseEvent) => e.preventDefault()
    canvas.addEventListener("mousedown", down); canvas.addEventListener("mouseup", up); canvas.addEventListener("mousemove", move); canvas.addEventListener("contextmenu", menu)
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); canvas.removeEventListener("mousedown", down); canvas.removeEventListener("mouseup", up); canvas.removeEventListener("mousemove", move); canvas.removeEventListener("contextmenu", menu) }
  }, [])

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-black p-4">
      <canvas ref={canvasRef} className="border border-gray-800 rounded-lg shadow-2xl" style={{ maxWidth: "100%", height: "auto" }} />
      <p className="mt-4 text-gray-400 text-xs text-center">Right-click and hold to scatter particles. Words change every 4 seconds.</p>
    </div>
  )
}
```

## Demo
```tsx
import { ParticleTextEffect } from "@/components/ui/particle-text-effect";

export default function DemoOne() {
  return <ParticleTextEffect />;
}
```

## Notes
- Canvas is fixed at 1000×500px — scale with CSS (`max-width: 100%; height: auto`) for responsive layouts.
- Words cycle automatically every 240 animation frames (~4 seconds at 60fps). Pass a custom `words` array to change the content.
